public static int levenshtein(String source, String target) {
    int m = source.length();
    int n = target.length();

    int[] v0 = new int[n + 1];
    int[] v1 = new int[n + 1];

    for (int i = 0; i <= m; i++) {
        v0[0] = i;
        int[] t = v0;
        v0 = v1;
        v1 = t;
    }

    for (int i = 0; i < n; i++) {
        v1[i] = i;
    }

    for (int i = 0; i < m; i++) {
        v1[n] = i + 1;
